INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Xuanyao (Kelvin) Fong', 'Asst. Prof.', 'Xuanyao (Kelvin)', 'Fong', 'Principal Investigator', 'Principal Investigator', 0, '__ASSET_BASE__/seed-assets/photos/Xuanyao (Kelvin) FONG_83e69604.png', 'Dr. Kelvin Fong Xuanyao (Student \'06, M\'14, IEEE) received his B.Sc. with distinction and Ph.D. degrees in Electrical Engineering from Purdue University, West Lafayette, IN, USA in 2006 and 2014, respectively.

Since December 2016, Dr. Kelvin Fong is an Assistant Professor in the Department of Electrical & Computer Engineering at the National University of Singapore. He was an Intern Engineer with the Global Circuits Group (Bulldozer) at Advanced Micro Devices, Inc. Boxborough Design Center in Massachusetts from January 2007 to August 2007. He was then a Postdoctoral Research Assistant supervised by Prof. Kaushik Roy in the School of Electrical and Computer Engineering, Purdue University, West Lafayette, IN from September 2014 to May 2015. He then joined the Institute of Microelectronics at the Agency for Science, Technology and Research (A*STAR), Singapore, as a Research Scientist in June 2015.

The primary research interests of Dr. Fong include hardware-software co-design of scalable energy efficient electronics, and interactions across the materials-devices-circuits-architectures-algorithms stack. He has served as Associate Editor in IEEE Electron Device Letters (EDL), Journal on Exploratory Solid-State Computational Devices and Circuits (JxCDC), Transactions on Very Large-Scale Integration Systems (TVLSI), and Transactions on Circuits and Systems - I (TCAS-I); the Journal on Low-Power Electronics and Applications, and Interdiscipline. He has also served on the technical program committees of ICCAD (\'26, \'25, \'24), DAC (\'26, \'25), CCMCC (\'26), EDTM (\'26, \'24), ASSCC (\'26, \'25), ICONS (\'23, \'22, \'21), and BioCAS (\'23); and was in the organizing committee for ISCAS\'24 and CAS-related conferences/workshops. He was also the recipient of the "AMD Design Excellence Award" at Purdue in 2008.', 'kelvin.xy.fong@nus.edu.sg', '', 0, '2026-03-20 05:48:37', '2026-07-16 13:27:10');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Jianze Wang', '', 'Jianze', 'Wang', 'Graduate Student (PhD)', 'Graduate Student (Ph.D.)', 0, '__ASSET_BASE__/seed-assets/photos/Jianze WANG_6c75f853.jpg', 'Wang Jianze received his B.S. degree in Electronic Information Science and Technology from University of Electronic Science and Technology of China (UESTC) in 2019, and M.S. degree in Electrical Engineering from National University of Singapore (NUS) in 2020. He used to work on spiking neural network using GPU acceleration under Prof. Fong\'s supervision.', 'jianze.wang@u.nus.edu', '', 0, '2026-03-20 05:48:37', '2026-03-21 06:45:18');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Yunuo Cen', '', 'Yunuo', 'Cen', 'Graduate Student (Ph.D.)', 'Graduate Student (Ph.D.)', 1, '__ASSET_BASE__/seed-assets/photos/Yunuo CEN_7c4731e3.jpg', 'Cen Yunuo received his B.E. degree in Macromolecular Materials and Engineering from Shenzhen University (SZU) in 2020, and M.S. degree in Electrical Engineering from National University of Singapore (NUS) in 2021. He is currently pursuing his Ph.D. at NUS supervised by Asst. Prof. Xuanyao Fong (Kelvin). His research focuses on hardware-algorithm codesign for Ising machine and neuromorphic computing.', 'cenyunuo@u.nus.edu', '', 0, '2026-03-20 05:48:37', '2026-07-16 12:54:22');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Yimin Wang', '', 'Yimin', 'Wang', 'Graduate Student (Ph.D.)', 'Graduate Student (Ph.D.)', 1, '__ASSET_BASE__/seed-assets/photos/Yimin WANG_402465ba.png', 'Wang Yimin received his B.S. degree in Electronic Information Science and Technology in 2019 from Jilin University (JLU), China, and M.S. degree in Electrical Engineering in 2022 from National University of Singapore (NUS). He is currently pursuing his Ph.D. at NUS supervised by Prof. Xuanyao Fong (Kelvin). His research focuses on efficient hardware design for intelligent electronic systems, including spiking neural network accelerator and Ising machines.', 'yimin.wang@u.nus.edu', '', 0, '2026-03-20 05:48:37', '2026-07-16 12:54:22');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wei Zhang', '', 'Wei', 'Zhang', 'Graduate Student (PhD)', 'Graduate Student (Ph.D.)', 0, '__ASSET_BASE__/seed-assets/photos/Wei ZHANG_a8a311f3.png', 'Zhang Wei received his B.Eng. degree as Excellent Graduate in Microelectronic Science and Engineering from Soochow University (SCU) in 2021, and M.Sc. degree in Electrical Engineering from National University of Singapore (NUS) in 2022. He is currently pursuing his Ph.D. at NUS supervised by Asst. Prof. Xuanyao Fong (Kelvin). His research focuses on modeling of ferroelectric memory devices for edge-AI system.', 'zhwei98@nus.edu.sg', '', 0, '2026-03-20 08:27:23', '2026-03-21 06:45:18');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Zhen Wu', '', 'Zhen', 'Wu', 'Graduate Student (PhD)', 'Graduate Student (Ph.D.)', 0, '__ASSET_BASE__/seed-assets/photos/Zhen WU_aa188b07.png', 'Wu Zhen received his Bachelor\'s degree in Electrical Engineering from the National University of Singapore (NUS) in June 2022. He is working towards a Ph.D. at NUS under Prof. Kelvin Fong\'s guidance. His research focus on microarchitectures for ultra-energy efficient domain-specific computing machines.', 'e0323083@u.nus.edu', '', 0, '2026-03-20 08:27:23', '2026-03-21 06:45:18');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Zixuan Wang', '', 'Zixuan', 'Wang', 'Graduate Student (PhD)', 'Graduate Student (Ph.D.)', 0, '__ASSET_BASE__/seed-assets/photos/Zixuan WANG_fff31661.png', 'Wang Zixuan received his B.S degree in Electronic Science and Technology from Beijing Institute of Technology (BIT) in 2021, and M.S. degree in Electrical and Computer Engineering from Georgia Institute of Technology (GT) in 2023. He is currently pursuing his Ph.D. at NUS supervised by Prof. Fong Xuanyao (Kelvin). His research focuses on combinatorial optimization problems and artificial intelligence hardware accelerator.', 'zixuanwang@u.nus.edu', '', 0, '2026-03-20 08:27:23', '2026-03-21 06:45:18');
