INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Archishman Saha', NULL, 'Archishman', 'Saha', 'Undergraduate Student', 'UREx (IIT Bombay, India)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Archishman-SAHA_c740b056.png', 'Archishman is an Electrical Engineering undergraduate student at Indian Institute of Technology Bombay (IIT Bombay), India, expected to graduate with a integrated B.Tech. and M.Tech. degree by 2023. He has been working as a Research Intern in the SEEDER group at National University of Singapore under the supervision of Prof Xuanyao Fong, since Summer 2020, and has worked on modelling spintronic and ferroelectric devices.', 'archishman@ee.iitb.ac.in', NULL, 0, '2026-03-21 06:18:41', '2026-03-27 02:11:37');
