INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Debasis Das', NULL, 'Debasis', 'Das', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Debasis-DAS_6014c551.jpg', 'Dr. Debasis Das received a B.Sc. degree in Electronic Science in 2009 from the University of Calcutta, India, M.Sc. degree in Electronic Science in 2011, M.Tech. degree in Nanoscience and Nanotechnology in 2013, from Jadavpur University, India. He has completed his Ph.D. degree in Electrical Engineering from the Indian Institute of Technology (IIT), Bombay, India, in 2019. He has been working as a Research Fellow in the SEEDER group at the National University of Singapore since 2019. His research interests include the physics and simulation of spintronic-based nanoscale devices such as Magnetic Tunnel Junction, Skyrmion based devices, and its application in neuromorphic computation.', 'eledd@nus.edu.sg', NULL, 0, '2026-03-21 06:21:49', '2026-03-27 02:11:39');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Denys Riwan Bunsothy Ly', NULL, 'Denys Riwan Bunsothy', 'Ly', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Denys-LY_caa9f54c.png', 'Dr. Denys R. B. Ly received his M. Eng. degree in analog and digital circuit design from Grenoble INP Engineering School, France in 2016. He attained his PhD in Nanoelectronics and Nanotechnologies from Grenoble Alpes University and CEA-Leti, France in 2019 and worked as a Postdoctoral Research Fellow in the SEEDER group of National University of Singapore (NUS), Singapore, from 2021 to 2022. Currently, he is working as a Research Engineer in CEA-Leti, France. His research interests are in the field of emerging non-volatile memories, spanning from device and circuit electrical characterisation, memory circuit design, and use of non-volatile memories to implement non-conventional computing paradigms.', 'drb.ly@nus.edu.sg', NULL, 0, '2026-03-21 06:21:49', '2026-03-27 02:11:39');
