INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Qinghao Hu', NULL, 'Qinghao', 'Hu', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-HU-Qinghao_b7afd040.jpg', 'HU Qinghao is a Ph.D. candidate of School of Computer Science and Engineering at Nanyang Technological University. He received his M.S. degree in Electrical Engineering from National University of Singapore, and B.E. degree from Zhejiang University. His research interests include deep learning and distributed system. His research work was compact device modeling for future transistor technologies using neural networks.', 'qinghao@u.nus.edu', NULL, 0, '2026-03-21 06:26:35', '2026-07-16 12:54:23');
