INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Haotian Lu', NULL, 'Haotian', 'Lu', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Haotian-LU_025dd715.png', 'Haotian Lu received the B.E. degree in Microelectronics from Tianjin University, Tianjin, China in 2023. He is currently a postgraduate student in the department of Electrical and Computer Engineering, National University of Singapore, Singapore, under the guidance of Prof. Kelvin Fong. His research interests mainly include algorithm and architecture design, neuromorphic computing, efficient AI hardware and hardware security.', 'haotian_lu@u.nus.edu', NULL, 0, '2026-03-21 06:26:35', '2026-07-16 12:54:24');
