INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Li Yang Kat', NULL, 'Li Yang', 'Kat', 'Undergraduate Student', 'Undergraduate Student (B.Eng., FYP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-KAT-LiYang_5195bd59.png', 'Li Yang was previously pursuing his Bachelor\'s degree in Electrical Engineering at the National University of Singapore. He is completing his Final Year Project under the guidance and support of Asst. Prof. Fong in the SEEDER group. He has diverse research interests and is always open to exploring new areas of research. He hopes to enable others through his engineering work in the future.', 'kat.liyang@u.nus.edu', NULL, 0, '2026-03-21 06:31:02', '2026-03-27 02:11:44');
