INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wenlan Li', NULL, 'Wenlan', 'Li', 'Graduate Student', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-LI-Wenlan_af9eb9dd.jpg', 'Li Wenlan received her Bachelor\'s degree in Automation from Tianjin University, China in 2020. Currently, she is pursuing the M.Sc in Electrical Engineering  at the National University of Singapore. Her research interests includes the modeling and simulation of ferroelectric capacitor, its intrinsic material properties and capacitance tomography system.', 'e0572650@u.nus.edu', NULL, 0, '2026-03-21 06:33:11', '2026-03-27 02:11:44');
