INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Tiedong Liu', NULL, 'Tiedong', 'Liu', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-LIU-Tiedong_e60fde19.jpg', 'Liu Tiedong is a third-year B.E (Electrical Engineering) student in National University of Singapore (NUS). He is currently taking the Undergraduate Research Oppotunity Programme (UROP) under the supervision of Prof. Kelvin Fong. His interests are in FPGA hardware accelerator design and neuromorphic computing.', 'e0325301@u.nus.edu', NULL, 0, '2026-03-21 06:33:11', '2026-03-27 02:11:45');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Zhiyang, Frank Liu', NULL, 'Zhiyang, Frank', 'Liu', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, NULL, '', 'liuzhiyang@u.nus.edu', NULL, 0, '2026-03-21 06:33:11', '2026-03-27 02:11:45');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Zhen Guang Jeffrey Low', NULL, 'Zhen Guang Jeffrey', 'Low', 'Undergraduate Student', 'Undergraduate Student (B.Eng., FYP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-LOW-ZhenGuang_b39bb668.jpg', 'Jeffrey is a final year B.E (Electrical Engineering) student in the National University of Singapore (NUS). He is working on a final-year project under the supervision of Prof. Kelvin Fong. He aspires to be a FPGA engineer specializing in hardware acceleration for algorithms with research interests in acceleration of computer vision, neural network, and neuromorphic algorithms. He believes that dedicated hardware is the future of better algorithm performance.', 'jeffrey@u.nus.edu', NULL, 0, '2026-03-21 06:35:02', '2026-03-27 02:11:45');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Zonghan, Kelly Lu', NULL, 'Zonghan, Kelly', 'Lu', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-LU-Zonghan_68ec9531.png', 'Zonghan is pursing in a Bachelor\'s degree in Electrical Engineering at the National University of Singapore (NUS). She is working on Spin-transfer torque (STT) and Spin-orbit torque (SOT) magnetic memories under Prof Fong\'s supervision along with Dr. Debasis\'s guidance.', 'e0492452@u.nus.edu', NULL, 0, '2026-03-21 06:35:02', '2026-03-27 02:11:45');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Ngoc Nhu Thao Nguyen', NULL, 'Ngoc Nhu Thao', 'Nguyen', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, '__ASSET_BASE__/seed-assets/photos/alumni-NGUYEN-NhuThao_3ac5133d.png', 'Thao received her Bachelor\'s degree in Computer Engineering from the National University of Singapore (NUS) in 2015. She is working towards a PhD at NUS under the guidance of Prof. Kelvin Fong and Prof. Bharadwaj Veeravalli. Her research interests include machine learning and neuromorphic computing.', 'thao@nus.edu.sg', NULL, 0, '2026-03-21 06:35:02', '2026-03-27 02:11:46');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Van Binh Nguyen', NULL, 'Van Binh', 'Nguyen', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-NGUYEN-VanBinh_6180e6eb.png', 'Binh is pursuing a Bachelor\'s degree in Computer Engineering with minors in Management and Data Engineering at the National University of Singapore (NUS). He is working on spiking neural network accelerators under Prof. Fong\'s supervision along with Thao and Yimin\'s guidance.', 'nguyen.binh@u.nus.edu', NULL, 0, '2026-03-21 06:35:02', '2026-03-27 02:11:46');
