INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Nehru Kandasamy', NULL, 'Nehru', 'Kandasamy', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, NULL, 'Dr. Nehru Kandasamy received his B.E. degree in Electronics and Instrumentation Engineering from Erode Sengunthar Engineering College, India in 2005, M.E. degree in VLSI design from R.M.K Engineering College, India in 2007 and Ph.D. degree in Information and Communication Engineering from Anna University, India in 2014. Currently, he is a Research Fellow in the SEEDER group at the National University of Singapore. His research interests are in the Low Power VLSI, Logic in Memory Circuits, Quantum Dot Cellular Automata and Non-Volatile Memory Technologies.', 'elenehr@nus.edu.sg', NULL, 0, '2026-03-21 06:37:35', '2026-03-27 02:11:47');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Putta Prabhu Thapaswini', NULL, 'Putta Prabhu', 'Thapaswini', 'Graduate Student (Ph.D.)', 'Graduate Student (Ph.D.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-PuttaPrabhu-THAPASWINI_629d79b2.png', 'Putta Prabhu Thapaswini received her B.E. degree in Electronics and Communication Engineering from Osmania University and the Master\'s degree in VLSI design from VIT University in 2014 and 2016 respectively. She was previously pursuing her PhD in Electrical Engineering at National University of Singapore (NUS) under the guidance of Prof. Aaron Voon-Yew THEAN and Asst. Prof. FONG Xuanyao, Kelvin. Her primary research area is Flexible Electronics.', 'e0204942@u.nus.edu', NULL, 0, '2026-03-21 06:37:35', '2026-07-16 12:54:22');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Hansi Qian', NULL, 'Hansi', 'Qian', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, NULL, '', 'e0724670@u.nus.edu', NULL, 0, '2026-03-21 06:37:35', '2026-07-16 12:54:25');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Chuping Qu', NULL, 'Chuping', 'Qu', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-QU-Chuping_c42e32d4.jpg', 'Qu Chuping received his BEng (Electrical Engineering) from the National University of Singapore (NUS) in 2017. Currently, he is pursuing his part-time M.Sc (Electrical Engineering) in NUS, while working as a research engineer at the Institute of High Performance Computing (IHPC), Computing & Intelligence department. He focuses on FPGA hardware designs for neuromorphic emulation and acceleration.', 'e0570673@u.nus.edu', NULL, 0, '2026-03-21 06:37:35', '2026-07-16 12:54:25');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Rahul Kale', NULL, 'Rahul', 'Kale', 'Staff', 'Research Engineer', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Rahul-KALE_ae35924e.png', 'Rahul received his B.Tech. degree in Electronics Engineering from VJTI, Mumbai, in 2014 and M.Sc in Electrical Engineering with specialization in Computer Engineering from the National University of Singapore (NUS) in 2016. He has been working as a Research Engineer at NUS since 2016. His research interests include cybersecurity in cloud computing, machine learning and FPGA.', 'elekrv@nus.edu.sg', NULL, 0, '2026-03-21 06:37:35', '2026-03-27 02:12:09');
