INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Shi Peishu', NULL, 'Peishu', 'Shi', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-SHI-Peishu_fed786ae.png', 'Peishu Shi received his B. Tech degree in Optoelectronic Information from University of Electronic Science and Technology of China, in 2017. He was previously pursuing his Master degree at the Department of Electrical & Computer Engineering in the National University of Singapore. His research interests include machine learning and FPGA.', 'e0251036@u.nus.edu', NULL, 0, '2026-03-21 06:37:35', '2026-07-16 12:54:25');
