INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Sanjeeb Bharali', NULL, 'Sanjeeb', 'Bharali', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Sanjeeb-BHARALI_37c45254.jpg', 'Sanjeeb received his B.E. in Electronics and Telecommunication Engineering from the University of Mumbai, India, in 2018, and his MSc in Electrical Engineering, specializing in Nanoelectronics, from the National University of Singapore, in 2020. He is a recipient of the "Technical Excellence Award 2018" and "Mr Sriram Suresh Endowment Award in 2019," awarded by the South Indian Education Society (SIES). His primary research interest lies in the design of non-volatile memories; MRAMs and Ferroelectric FET based memories in particular.', 'sanjeeb.b@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-07-16 12:54:23');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Sathyanarayanan Muralidharan', NULL, 'Sathyanarayanan', 'Muralidharan', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, NULL, '', 'e0024526@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-07-16 12:54:24');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Shreyas NANDI', NULL, 'Shreyas', 'NANDI', 'Staff', 'Research Engineer', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Shreyas-NANDI_6a7f0d7c.png', 'Shreyas Nandi received his B.E. degree from Birla Institute of Technology and Science, Pilani, Hyderabad, in 2017. Prior to joining the SEEDER group, he worked on his bachelor dissertation titled "Calibration of Solar Cell Simulation Models" at the National University of Singapore. He has worked as a summer intern at Texas Instruments, Bangalore in 2015 and was also a recipient of Summer Research Fellowship in 2016 from Indian Academy of Science for summer internship at IISC Bangalore. His current research work includes compact device modeling of spintronic devices and Integrated Circuit design.', 'shreyas.nandi@nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-03-21 06:40:00');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Shyam Krishnan Venkateswaran', NULL, 'Shyam Krishnan', 'Venkateswaran', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Shyam-VENKATESWARAN_194502ef.png', 'Shyam received his B.E. degree in Electronics and Communication Engineering from College of Engineering, Guindy (CEG), India, in 2016. He worked with Bharti Airtel as Young Technical Leader for over an year and was involved in Radio Planning. He was previously pursuing Masters in National University of Singapore. His primary research interests include Digital communication and Machine learning.', 'e0269730@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-07-16 12:54:26');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Siddhartha Raman', NULL, 'Siddhartha', 'Raman', 'Undergraduate Student', 'UREx (BITS Pilani, India)', 1, NULL, '', 'f20150572@hyderabad.bits/pilani.ac.in', NULL, 0, '2026-03-21 06:40:00', '2026-03-27 02:12:11');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Sifan Li', NULL, 'Sifan', 'Li', 'Graduate Student', 'Graduate Student (Ph.D.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Sifan-LI_0f626368.jpg', 'Li Sifan received his Bachelor\'s degree in physics from University of Chinese Academy of Science (UCAS) in 2018. He is currently pursuing his Ph.D. at National University of Singapore (NUS) under the guidance of Assoc. Prof. Ang Kah-Wee and Asst. Prof. Xuanyao Fong (Kelvin). His research focuses on 2-dimensional material based memristive devices and their applications for neuromorphic computing.', 'sifan.li@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-03-27 02:12:11');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Subhranu Samanta', NULL, 'Subhranu', 'Samanta', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Subhranu-SAMANTA_525b6230.png', 'Dr. Subhranu Samanta received his B.Sc and M.Sc. degrees in Physics from Vidyasagar University, India in 2008 and 2010, respectively. He attained his PhD in Electronics Engineering from Chang Gung University, Taiwan in 2018. Currently, he is a research fellow in the SEEDER group at the National University of Singapore. His present research interests are in device fabrication and mechanism exploration for high density neuromorphic resistive RAM and thin film transistor (TFT).', 'elesam@nus.edu.sg', NULL, 0, '2026-03-21 06:40:00', '2026-03-27 02:12:11');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Suhasini Komarraju', NULL, 'Suhasini', 'Komarraju', 'Graduate Student', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Suhasini-KOMARRAJU_b23d9b05.png', 'Suhasini received her Bachelors degree in Electronics and Communication Engineering from Indian Institute of Technology Roorkee (IIT Roorkee), India, in 2016. She then worked as 4G-Technical Lead in Bharti Airtel, India, till 2017 December. She was previously pursuing her Masters degree at the National University of Singapore. Her primary research interest lies in communications. She is currently exploring Machine learning techniques.', 'e0269729@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-03-27 02:12:12');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Suyang Liu', NULL, 'Suyang', 'Liu', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Suyang-LIU_f0c3d246.png', 'Liu Suyang received his Bachelor\'s degree in Electronic Information Engineering from Nanjing University of Aeronautics and Astronautics (NUAA) in 2023. He is pursuing his Master\'s degree at the Department of Electrical & Computer Engineering at the National University of Singapore. His research interests include designing an integrated functionalized memory subsystem and analog integrated circuits design.', 'e1143555@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-07-16 12:54:24');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Ru Phing Tan', NULL, 'Ru Phing', 'Tan', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-TAN-RuPhing_5ec16e86.jpg', 'Ru Phing received her BASc in Electrical Engineering from University of British Columbia in 2015. She was also an engineer at Intel before pursuing her Master\'s degree in Electrical Engineering at NUS in 2019. Under Prof Fong\'s guidance, she worked on the compact modelling of emerging transistors using neural networks.', 'e0384913@u.nus.edu', NULL, 0, '2026-03-21 06:40:00', '2026-07-16 12:54:26');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Varun Shaji', NULL, 'Varun', 'Shaji', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Varun-SHAJI_5776e0d0.jpg', 'Varun is a final year B.E (Electrical Engineering) student in National University of Singapore (NUS). He is currently taking the Undergraduate Research Opportunity Programme (UROP) under the supervision of Prof. Kelvin Fong. His interests are in embedded hardware systems, neuromorphic computing, and signal processing. Outside of work, he enjoys painting, cooking, and following current affairs.', 'varun.shaji@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-03-27 02:12:12');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Venkata Pavan Kumar Miriyala', NULL, 'Venkata Pavan Kumar', 'Miriyala', 'Graduate Student (Ph.D.)', 'Graduate Student (Ph.D.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-VenkataPavanKumar-MIRIYALA_c9748681.png', 'Pavan has received his Bachelor\'s degree in Electronics and Communication Engineering from SSN Engineering College, India in 2014. Later, he worked as a research assistant in Indian Institute of Technology (IIT), Hyderabad for one year. He is currently working towards a PhD at the National University of Singapore under the guidance of Assoc. Prof. Liang Gengchiau (Albert) and Asst. Prof. Xuanyao Fong (Kelvin). His research interests include the device physics and modelling of spintronic boolean and non-boolean logic devices.', 'elevpkm@nus.edu.sg', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:22');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wang Jingyuanzhang', NULL, 'Jingyuanzhang', 'Wang', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-WANG-Jingyuanzhang_4917be1c.jpg', 'Wang Jingyuanzhang received his B.S. degree in Microelectronics from UESTC, China in 2019 and MSc degree in Electrical Engineering from NUS, Singapore in 2020. His research interest was the development of FPGA-based SNN hardware accelerator.', 'e0427482@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:26');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wang Mingzhu', NULL, 'Mingzhu', 'Wang', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, NULL, '', 'e0320945@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:26');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wang Yuanjian', NULL, 'Yuanjian', 'Wang', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, NULL, '', 'wangyuanjian@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:27');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wang Yuxin', NULL, 'Yuxin', 'Wang', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-WANG-Yuxin_a9a6b3ba.png', 'Yuxin Wang received his B.S. degree in Microelectronic Science and Engineering from Xidian University, China in 2017. He is currently pursuing his M.Sc degree at the Department of Electrical and Computer Engineering in the National University of Singapore. He was previously working in the SEEDER group with a research focus on neuromorphic computing using memristor based devices.', 'e0251038@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:27');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wancheng Wu', NULL, 'Wancheng', 'Wu', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-WU-Wancheng_55b1b615.jpg', 'Wu Wancheng received his MSc degree in Electrical Engineering from National University of Singapore (NUS) in 2020, and B.E. degree from University of Electronic Science and Technology of China (UESTC) in 2018. He used to work on neural network modelling of 6T SRAM with optimization algorithms under Prof Fong\'s guidance.', 'e0383692@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:27');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wei Pin Chua', NULL, 'Wei Pin', 'Chua', 'Undergraduate Student', 'Undergraduate Student (B.Eng., UROP)', 1, NULL, '', 'e0298669@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-03-27 02:12:14');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Wilbert Biao-Hui Tan', NULL, 'Wilbert Biao-Hui', 'Tan', 'Undergraduate Student', 'Undergraduate Student (B.Eng., FYP)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Wilbert-TAN_b3d2a8ae.jpg', 'Wilbert is a final year B.E (Electrical Engineering) and University Scholar Program student in the National University of Singapore (NUS). He is working on his final-year project under the supervision of Prof. Kelvin Fong. His primary research interest focuses on combining the worlds of biological and electrical design. Currently, he is exploring possible applications of magnetic skyrmion-based devices in neuromorphic computing. Outside of the lab, he enjoys cooking, eating and playing basketball.', 'wilbert.tan@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-03-27 02:12:14');
