INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Yuhang Xie', NULL, 'Yuhang', 'Xie', 'Graduate Student (M.Sc.)', 'Graduate Student (M.Sc.)', 1, '__ASSET_BASE__/seed-assets/photos/alumni-Yuhang-XIE_fc240c59.png', 'Xie Yuhang received his B.S. in Communication Engineering from Xidian University in 2022. He is now pursuing an M.Sc in Electrical Engineering at the National University of Singapore. His current research focuses on building and optimizing phase-field models for ferroelectric materials and exploring their application in IGZO FeFET memory devices.', 'xieyuhang@u.nus.edu', NULL, 0, '2026-03-21 06:42:46', '2026-07-16 12:54:27');
INSERT INTO `team_members` (`id`, `name`, `title`, `firstName`, `lastName`, `category`, `role`, `isAlumni`, `photoUrl`, `biography`, `email`, `researchInterests`, `displayOrder`, `createdAt`, `updatedAt`) VALUES (1, 'Panpan Zhang', NULL, 'Panpan', 'Zhang', 'Postdoctoral Fellow', 'Post-doctoral Research Fellow', 1, '__ASSET_BASE__/seed-assets/photos/alumni-ZHANG-Panpan_f3900feb.png', 'Dr. Zhang Panpan received her B.S. degree in Microelectronics from Nankai University, China in 2012, and Ph.D. degree in Physical Electronics from Peking University, China in 2017. Currently, she is a Research Fellow in the SEEDER group at the National University of Singapore. Her research interests are in the modeling and development of Process Design Kit for Carbon Nanotube based devices, and flexible electronics.', 'elezhp@nus.edu.sg', NULL, 0, '2026-03-21 06:42:46', '2026-03-27 02:12:16');
