INSERT INTO `publications` (`id`, `title`, `authors`, `year`, `publicationDate`, `journal`, `pages`, `doi`, `link`, `bibtex`, `abstract`, `createdAt`, `updatedAt`, `url`, `relatedProjects`, `pubType`) VALUES (1, 'On-Chip Non-volatile STT-MRAM for Zero-Standby Power', 'Xuanyao Fong, Kaushik Roy', 1, '2017', 'Enabling the Internet of Things', '213-246', '10.1007/978-3-319-51482-6_7', NULL, '@Inbook{Fong2017,
author="Fong, Xuanyao
and Roy, Kaushik",
editor="Alioto, Massimo",
title="On-Chip Non-volatile STT-MRAM for Zero-Standby Power",
bookTitle="Enabling the Internet of Things: From Integrated Circuits to Integrated Systems",
year="2017",
publisher="Springer International Publishing",
address="Cham",
pages="213--246",
abstract="In this Chapter, we present spin-transfer torque magnetic random access memory (STT-MRAM) suitable for IoT applications. Its ability to operate at low supply voltages, non-volatility, good endurance, and small bit-cell footprint are especially attractive for IoT applications in which low energy consumption is crucial. We will present the fundamentals of STT-MRAM. The design of the STT-MRAM storage device, memory bit-cell and memory array architecture are also discussed to highlight the benefits STT-MRAM brings to IoT applications, as well as the design issues that need to be considered. We then present a device/circuit/architecture co-design approach for STT-MRAM. Finally, we will discuss the trends in STT-MRAM and give some perspectives on the future of STT-MRAM design.",
isbn="978-3-319-51482-6",
doi="10.1007/978-3-319-51482-6_7",
url="https://doi.org/10.1007/978-3-319-51482-6_7"
}
', 'In this Chapter, we present spin-transfer torque magnetic random access memory (STT-MRAM) suitable for IoT applications. Its ability to operate at low supply voltages, non-volatility, good endurance, and small bit-cell footprint are especially attractive for IoT applications in which low energy consumption is crucial. We will present the fundamentals of STT-MRAM. The design of the STT-MRAM storage device, memory bit-cell and memory array architecture are also discussed to highlight the benefits STT-MRAM brings to IoT applications, as well as the design issues that need to be considered. We then present a device/circuit/architecture co-design approach for STT-MRAM. Finally, we will discuss the trends in STT-MRAM and give some perspectives on the future of STT-MRAM design.', '2026-03-16 09:01:17', '2026-03-16 09:01:17', 'https://doi.org/10.1007/978-3-319-51482-6_7', '', 'journal');
