INSERT INTO `research_projects` (`id`, `title`, `slug`, `description`, `fullContent`, `imageUrl`, `tags`, `isActive`, `displayOrder`, `createdAt`, `updatedAt`, `galleryImages`) VALUES (1, 'Ferroelectric Transistors', 'ferroelectric-transistors', 'The ferroelectric transistor (FeFET) represents a promising technology for non-volatile memory and neuromorphic computing applications. Our research investigates the physics and variability of ferroelectric devices integrated with advanced channel materials, particularly focusing on back-end-of-line (BEOL) compatible architectures using oxide semiconductors and 2D materials.

We employ comprehensive modeling frameworks combining Voronoi algorithms for grain pattern simulation with physics-based TCAD and phase-field simulations to understand intrinsic variability sources. Key findings reveal that polycrystalline grain structures significantly influence device performance through grain boundary effects, crystalline orientation fluctuations, and ferroelectric domain dynamics. Device-to-device variability increases dramatically at nanoscale dimensions, with coercive field and remnant polarization showing strong dependence on grain size and polar-axis orientation.

Our work addresses critical challenges in achieving reliable ferroelectric memory devices through grain engineering strategies and optimization of polarization switching mechanisms. By integrating ferroelectric materials with oxide semiconductors, we enable BEOL-compatible integration for advanced memory and computing applications. The research provides design guidelines for device operation and demonstrates pathways toward high-performance, scalable ferroelectric technologies for AI inference, edge computing, and in-memory computing systems.', NULL, '__ASSET_BASE__/seed-assets/photos/hero_image_5aec60ee.png', 'ferroelectric transistor,process variations,nonvolatile memory,modeling & simulation', 1, 1, '2026-03-18 16:58:05', '2026-03-18 16:58:05', '[object Object],[object Object],[object Object],[object Object],[object Object]');

